#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_omp(float *m, int matrix_dim) {
    int i, j, k, offset;

    for (offset = 0; offset < matrix_dim - BLOCK_SIZE; offset += BLOCK_SIZE) {
        // lud_diagonal equivalent - process diagonal block
        float shadow[BLOCK_SIZE * BLOCK_SIZE];

        // Load diagonal block into shadow (equivalent to OpenCL local memory load)
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int array_offset = offset * matrix_dim + offset;
            for (i = 0; i < BLOCK_SIZE; i++) {
                shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                array_offset += matrix_dim;
            }
        }

        // LU decomposition on shadow (equivalent to OpenCL kernel computation)
        for (i = 0; i < BLOCK_SIZE - 1; i++) {
            // First part: update lower triangle
            #pragma omp parallel for
            for (int tx = i + 1; tx < BLOCK_SIZE; tx++) {
                for (j = 0; j < i; j++)
                    shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
                shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
            }

            // Second part: update upper triangle
            #pragma omp parallel for
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                for (j = 0; j < i + 1; j++)
                    shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
        }

        // Write back diagonal block (except first row which is already correct)
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int array_offset = (offset + 1) * matrix_dim + offset;
            for (i = 1; i < BLOCK_SIZE; i++) {
                m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
                array_offset += matrix_dim;
            }
        }

        // lud_perimeter equivalent - process perimeter blocks
        int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

        for (int bx = 0; bx < num_blocks; bx++) {
            float dia[BLOCK_SIZE * BLOCK_SIZE];
            float peri_row[BLOCK_SIZE * BLOCK_SIZE];
            float peri_col[BLOCK_SIZE * BLOCK_SIZE];

            // Load diagonal block
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    dia[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                    array_offset += matrix_dim;
                }
            }

            // Load perimeter row block
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_row[i * BLOCK_SIZE + tx] = m[array_offset + (bx + 1) * BLOCK_SIZE + tx];
                    array_offset += matrix_dim;
                }
            }

            // Load perimeter column block
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_col[i * BLOCK_SIZE + tx] = m[array_offset + tx];
                    array_offset += matrix_dim;
                }
            }

            // Update perimeter row
            #pragma omp parallel for
            for (i = 1; i < BLOCK_SIZE; i++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    for (j = 0; j < i; j++)
                        peri_row[i * BLOCK_SIZE + tx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + tx];
                }
            }

            // Update perimeter column
            #pragma omp parallel for
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    for (j = 0; j < i; j++)
                        peri_col[tx * BLOCK_SIZE + i] -= peri_col[tx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                    peri_col[tx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
                }
            }

            // Write back perimeter row
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = (offset + 1) * matrix_dim + offset;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    m[array_offset + (bx + 1) * BLOCK_SIZE + tx] = peri_row[i * BLOCK_SIZE + tx];
                    array_offset += matrix_dim;
                }
            }

            // Write back perimeter column
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    m[array_offset + tx] = peri_col[i * BLOCK_SIZE + tx];
                    array_offset += matrix_dim;
                }
            }
        }

        // lud_internal equivalent - process internal blocks
        #pragma omp parallel for collapse(2)
        for (int by = 0; by < num_blocks; by++) {
            for (int bx = 0; bx < num_blocks; bx++) {
                int global_row_id = offset + (by + 1) * BLOCK_SIZE;
                int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

                for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                        float sum = 0;
                        for (k = 0; k < BLOCK_SIZE; k++) {
                            sum += m[(global_row_id + ty) * matrix_dim + offset + k] * 
                                   m[(offset + ty) * matrix_dim + global_col_id + k];
                        }
                        m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                    }
                }
            }
        }
    }

    // Final diagonal block (last BLOCK_SIZE x BLOCK_SIZE)
    offset = matrix_dim - BLOCK_SIZE;
    float shadow[BLOCK_SIZE * BLOCK_SIZE];

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        int array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
            array_offset += matrix_dim;
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for
        for (int tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++)
                shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        #pragma omp parallel for
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++)
                shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
        }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        int array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
            array_offset += matrix_dim;
        }
    }
}
